from lxml import etree
import io

def process_soap_request(xml_content):
    # Create parser with DTD validation enabled
    parser = etree.XMLParser(
        dtd_validation=True,
        load_dtd=True,
        no_network=False,
        remove_blank_text=True,
        strip_cdata=False
    )
    
    try:
        # Parse the XML content
        root = etree.fromstring(xml_content, parser)
        
        # Define SOAP namespaces
        namespaces = {
            'soap': 'http://schemas.xmlsoap.org/soap/envelope/',
            'xsi': 'http://www.w3.org/2001/XMLSchema-instance',
            'xsd': 'http://www.w3.org/2001/XMLSchema'
        }
        
        # Find SOAP Envelope
        envelope = root.find('.//soap:Envelope', namespaces=namespaces)
        if envelope is None:
            raise ValueError("Invalid SOAP envelope")
        
        # Find SOAP Body
        body = envelope.find('.//soap:Body', namespaces=namespaces)
        if body is None:
            raise ValueError("SOAP body not found")
        
        # Extract message content
        message_content = {}
        for child in body:
            # Get element name and content
            element_name = child.tag.split('}')[-1] if '}' in child.tag else child.tag
            message_content[element_name] = etree.tostring(child, encoding='unicode', method='xml')
        
        return message_content
        
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML syntax: {str(e)}")
    except Exception as e:
        raise ValueError(f"Error processing SOAP request: {str(e)}")